module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output reg mul_en_out,
    output reg mul_out
);

reg [1:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
wire [15:0] temp[7:0];
reg [15:0] sum[7:0];
reg [15:0] mul_out_reg;

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_en_out_reg <= 2'b00;
        mul_a_reg <= 8'h00;
        mul_b_reg <= 8'h00;
        mul_out_reg <= 16'h0000;
    end else begin
        mul_en_out_reg <= {mul_en_out_reg[0], mul_en_in};
        mul_a_reg <= mul_en_in ? mul_a : mul_a_reg;
        mul_b_reg <= mul_en_in ? mul_b : mul_b_reg;

        assign temp[0] = mul_b_reg[0] ? {8'b00000000, mul_a_reg} : 16'b0000000000000000;
        assign temp[1] = mul_b_reg[1] ? {7'b0000000, mul_a_reg, 1'b0} : 16'b0000000000000000;
        assign temp[2] = mul_b_reg[2] ? {6'b000000, mul_a_reg, 2'b00} : 16'b0000000000000000;
        assign temp[3] = mul_b_reg[3] ? {5'b00000, mul_a_reg, 3'b000} : 16'b0000000000000000;
        assign temp[4] = mul_b_reg[4] ? {4'b0000, mul_a_reg, 4'b0000} : 16'b0000000000000000;
        assign temp[5] = mul_b_reg[5] ? {3'b000, mul_a_reg, 5'b00000} : 16'b0000000000000000;
        assign temp[6] = mul_b_reg[6] ? {2'b00, mul_a_reg, 6'b000000} : 16'b0000000000000000;
        assign temp[7] = mul_b_reg[7] ? {1'b0, mul_a_reg, 7'b0000000} : 16'b0000000000000000;

        sum[0] <= temp[0];
        sum[1] <= temp[1] + temp[0];
        sum[2] <= temp[2] + sum[1];
        sum[3] <= temp[3] + sum[2];
        sum[4] <= temp[4] + sum[3];
        sum[5] <= temp[5] + sum[4];
        sum[6] <= temp[6] + sum[5];
        sum[7] <= temp[7] + sum[6];

        mul_out_reg <= sum[0] + sum[1] + sum[2] + sum[3] + sum[4] + sum[5] + sum[6] + sum[7];
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_en_out <= 1'b0;
        mul_out <= 16'h0000;
    end else begin
        mul_en_out <= mul_en_out_reg[1];
        mul_out <= mul_en_out ? mul_out_reg : 16'h0000;
    end
end

endmodule
